const body = $input.first().json.body || $input.first().json;

const name = body.name || 'Unknown';
const phone = body.phone || 'Unknown';
const lat = body.lat || '0';
const lng = body.lng || '0';

const mapsLink = `https://www.google.com/maps?q=${lat},${lng}`;

return [{
  json: {
    name,
    phone,
    lat,
    lng,
    mapsLink
  }
}];

const data = $input.first().json;

const now = new Date();
const timestamp = now.toLocaleString('en-IN', {
  timeZone: 'Asia/Kolkata',
  dateStyle: 'full',
  timeStyle: 'long'
});

const message = `🚨 EMERGENCY ALERT 🚨\n\nName: ${data.name}\nPhone: ${data.phone}\n\n⚠️ I feel unsafe. Please help immediately.\n\n📍 Live Location:\n${data.mapsLink}\n\n⏰ Time: ${timestamp}`;

return [{
  json: {
    ...data,
    message,
    timestamp
  }
}];
